using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
struct edge
{
	int u,v,w;
	bool operator < (const edge &x) const
	{
		return w<x.w;
	}
};
multiset<edge> se;//multiset!!!!
int f[MAXN],n,m;
int find(int x)
{
	if(f[x]==x)return x;
	return f[x]=find(f[x]);
}
void merge(int x,int y)
{
	int fx=find(x),fy=find(y);
	if(fx==fy)return;
	f[fx]=fy;
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	n=read(),m=read();
	FOR(i,1,m)
	{
		int u=read(),v=read(),w=read();
		se.insert({u,v,w});
		FOR(j,1,n)f[j]=j;
		int j=n-1,ans=0;
		FOI(u,se)
		{
			if(j==0)break;
			int fx=find(u.u),fy=find(u.v);
			if(fx!=fy)
			{
				merge(u.u,u.v);
				ans=ans+u.w;
				--j;
			}
		}
		if(j)NoAns
		else writeln(ans);
	}
    return false;
}
